338	    fn matching_status_remote(
339	        &self,
340	        key_expr: &crate::key_expr::KeyExpr,
341	        destination: crate::sample::Locality,
342	        matching_type: crate::api::matching::MatchingStatusType,
343	        face_id: usize,
344	    ) -> crate::matching::MatchingStatus {
345	        use crate::matching::MatchingStatus;
346	
347	        let ns_key_expr = self
348	            .namespace
349	            .as_ref()
350	            .map(|ns| (ns / key_expr.deref()).into());
351	
352	        let router = self.router();
353	        let tables = zread!(router.tables.tables);
354	
355	        let (broker_hat, other_hats) = tables
356	            .hats
357	            .partition(&Region::Local)
358	            .expect("the local region should always have a corresponding hat");
359	        let local_broker = broker_hat
360	            .as_any()
361	            .downcast_ref::<hat::broker::Hat>()
362	            .expect("the local region's hat should always be the broker hat");
363	
364	        let key_expr = match &ns_key_expr {
365	            Some(ns_ke) => ns_ke,
366	            None => key_expr,
367	        };
368	
369	        let Some(src_face) = tables.data.faces.get(&face_id) else {
370	            tracing::error!(fid = face_id, "Unknown session face");
371	            return MatchingStatus { matching: false };
372	        };
373	
374	        let matching = match matching_type {
375	            crate::api::matching::MatchingStatusType::Subscribers => {
376	                local_broker.remote_subscriber_matching_status(
377	                    &tables.data,
378	                    src_face,
379	                    other_hats.map(|hat| &**hat as &dyn HatTrait), // FIXME(regions)
380	                    destination,
381	                    key_expr,
382	                )
383	            }
384	            crate::api::matching::MatchingStatusType::Queryables(complete) => {
385	                local_broker.remote_queryable_matching_status(
386	                    &tables.data,
387	                    src_face,
388	                    other_hats.map(|hat| &**hat as &dyn HatTrait), // FIXME(regions)
389	                    destination,
390	                    key_expr,
391	                    complete,
392	                )
393	            }
394	        };
395	
396	        MatchingStatus { matching }
397	    }
