406	                    .router
407	                    .new_session(Arc::new(ENamespace::new(ns.clone(), e_primitives)));
408	                (face.state.id, Arc::new(Namespace::new(ns.clone(), face)))
409	            }
410	            None => {
411	                let face = self.router.new_session(e_primitives);
