973	impl TransportEventHandler for RuntimeTransportEventHandler {
974	    #[tracing::instrument(level = "trace", skip_all)]
975	    fn new_unicast(
976	        &self,
977	        peer: TransportPeer,
978	        transport: TransportUnicast,
979	    ) -> ZResult<Arc<dyn TransportPeerEventHandler>> {
980	        match zread!(self.runtime).upgrade().as_ref() {
981	            Some(runtime) => {
982	                let _span = runtime.state.span.enter();
983	                let slave_handlers: Vec<Arc<dyn TransportPeerEventHandler>> =
984	                    zread!(runtime.state.transport_handlers)
985	                        .iter()
986	                        .filter_map(|handler| {
987	                            handler.new_unicast(peer.clone(), transport.clone()).ok()
988	                        })
989	                        .collect();
990	
991	                let config = runtime.config().lock().clone();
992	
993	                let (region, remote_bound) =
994	                    region::compute_region_of(&peer, &config, transport.get_bound()?.as_ref())?;
995	
996	                fn north_bound_transport_peer_count(
997	                    runtime: &Runtime,
998	                    new_peer: &TransportPeer,
999	                ) -> usize {
1000	                    ZRuntime::Application.block_in_place(async {
1001	                        runtime
1002	                            .manager()
1003	                            .get_transports_unicast()
1004	                            .await
1005	                            .iter()
1006	                            .filter(|transport| {
1007	                                let Ok(peer) = transport.get_peer() else {
1008	                                    tracing::error!(
1009	                                        "Could not get transport peer \
1010	                                        while computing north-bound transport count. \
1011	                                        Will ignore this transport"
1012	                                    );
1013	                                    return false;
1014	                                };
1015	
1016	                                let Ok(remote_bound) = transport.get_bound() else {
1017	                                    tracing::error!(
1018	                                        "Could not get transport remote bound \
1019	                                        while computing north-bound transport count. \
1020	                                        Will ignore this transport"
1021	                                    );
1022	                                    return false;
1023	                                };
1024	
1025	                                if &peer == new_peer {
1026	                                    return false;
1027	                                }
1028	
1029	                                // NOTE(regions): compute bound instead of querying the router as
1030	                                // the corresponding transport face might not exist yet
1031	                                let Ok((region, _)) = region::compute_region_of(
1032	                                    &peer,
1033	                                    &runtime.config().lock(),
1034	                                    remote_bound.as_ref(),
1035	                                ) else {
1036	                                    tracing::error!(
1037	                                        zid = %peer.zid.short(),
1038	                                        wai = %peer.whatami,
1039	                                        "Could not get transport peer region \
1040	                                        while computing north-bound transport count. \
1041	                                        Will ignore this transport"
1042	                                    );
1043	                                    return false;
1044	                                };
1045	
1046	                                region.bound().is_north()
1047	                            })
1048	                            .count()
1049	                    })
1050	                }
1051	
1052	                if region.bound().is_north()
1053	                    && runtime.whatami() == WhatAmI::Client
1054	                    && north_bound_transport_peer_count(runtime, &peer) > 0
1055	                {
1056	                    bail!("Client runtimes only accept one north-bound transport");
1057	                }
1058	
1059	                Ok(Arc::new(RuntimeSession {
1060	                    runtime: runtime.clone(),
1061	                    endpoints: std::sync::RwLock::new(HashSet::new()),
1062	                    main_handler: runtime
1063	                        .state
1064	                        .router
1065	                        .new_transport_unicast(transport, region, remote_bound)
1066	                        .unwrap(),
1067	                    slave_handlers,
1068	                }))
1069	            }
1070	            None => bail!("Runtime not yet ready!"),
1071	        }
1072	    }
1073	
1074	    fn new_multicast(
1075	        &self,
1076	        transport: TransportMulticast,
1077	    ) -> ZResult<Arc<dyn TransportMulticastEventHandler>> {
1078	        match zread!(self.runtime).upgrade().as_ref() {
1079	            Some(runtime) => {
1080	                let _span = runtime.state.span.enter();
1081	                let slave_handlers: Vec<Arc<dyn TransportMulticastEventHandler>> =
1082	                    zread!(runtime.state.transport_handlers)
1083	                        .iter()
1084	                        .filter_map(|handler| handler.new_multicast(transport.clone()).ok())
1085	                        .collect();
1086	
1087	                let region = region::compute_multicast_region(&runtime.config().lock())?;
1088	
1089	                runtime
1090	                    .state
1091	                    .router
1092	                    .new_transport_multicast(transport.clone(), region)?;
1093	                Ok(Arc::new(RuntimeMulticastGroup {
1094	                    runtime: runtime.clone(),
1095	                    transport,
1096	                    slave_handlers,
1097	                }))
1098	            }
1099	            None => bail!("Runtime not yet ready!"),
1100	        }
1101	    }
1102	}
