231	                unwrap_or_default!(guard.open().return_conditions().connect_scouted()),
232	                *unwrap_or_default!(guard.scouting().multicast().listen().peer()),
233	                AutoConnect::multicast(guard, WhatAmI::Peer, self.zid().into()),
234	                unwrap_or_default!(guard.scouting().multicast().address()),
235	                unwrap_or_default!(guard.scouting().multicast().interface()),
236	                Duration::from_millis(unwrap_or_default!(guard.scouting().delay())),
237	            )
